import{_ as e,o as l,c as n,ae as d}from"./chunks/framework.Ddp2KXB2.js";const a="/front-blog/js/base64Img/ASCII-table.jpeg",h=JSON.parse('{"title":"base64 详解","description":"","frontmatter":{},"headers":[],"relativePath":"pages/js/base64详解.md","filePath":"pages/js/base64详解.md"}'),r={name:"pages/js/base64详解.md"};function i(s,t,c,x,g,y){return l(),n("div",null,[...t[0]||(t[0]=[d('<h1 id="base64-详解" tabindex="-1">base64 详解 <a class="header-anchor" href="#base64-详解" aria-label="Permalink to &quot;base64 详解&quot;">​</a></h1><h2 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to &quot;目录&quot;">​</a></h2><ul><li>什么是base64</li><li>base64 如何编码</li><li>base64 如何解码</li></ul><h2 id="正文" tabindex="-1">正文 <a class="header-anchor" href="#正文" aria-label="Permalink to &quot;正文&quot;">​</a></h2><h3 id="什么是base64" tabindex="-1">什么是base64？ <a class="header-anchor" href="#什么是base64" aria-label="Permalink to &quot;什么是base64？&quot;">​</a></h3><p>以64个字符作为基本字符集（A-Z，a-z, 0-9, +, /）,此外还包含一个‘=’用作填充的字符（所以，总得来表示的话，总共有65个，但‘=’仅仅是在字符不够的情况下用于填充）。在基本字符集的基础纸上，用于表示其他字符。</p><h3 id="base64的编码规则" tabindex="-1">base64的编码规则 <a class="header-anchor" href="#base64的编码规则" aria-label="Permalink to &quot;base64的编码规则&quot;">​</a></h3><p>步骤如下：</p><ol><li>将原字符串由左往右，每三个字符划分为一组，最后不足三个的话，也划分为一组；</li><li>将每个字符 通过ascii码，查找对应的十进制值，再将十进制转换成二进制，一共氛围24个二进制位；</li><li>将24个二进制分为4组，每组6个，然后在每组的前面各加2个0，是每组变成8个二进制位，即4个字节；</li><li>将4组的二进制转换成十进制，然后在下面的base64表中，找到对应的字符，即base64编码的值</li></ol><h4 id="base64表" tabindex="-1">base64表 <a class="header-anchor" href="#base64表" aria-label="Permalink to &quot;base64表&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:center;">ASCII值</th><th style="text-align:center;">符号</th><th style="text-align:center;">ASCII值</th><th style="text-align:center;">符号</th><th style="text-align:center;">ASCII值</th><th style="text-align:center;">符号</th><th style="text-align:center;">ASCII值</th><th style="text-align:center;">符号</th></tr></thead><tbody><tr><td style="text-align:center;">0</td><td style="text-align:center;">A</td><td style="text-align:center;">1</td><td style="text-align:center;">B</td><td style="text-align:center;">2</td><td style="text-align:center;">C</td><td style="text-align:center;">3</td><td style="text-align:center;">D</td></tr><tr><td style="text-align:center;">4</td><td style="text-align:center;">E</td><td style="text-align:center;">5</td><td style="text-align:center;">F</td><td style="text-align:center;">6</td><td style="text-align:center;">G</td><td style="text-align:center;">7</td><td style="text-align:center;">H</td></tr><tr><td style="text-align:center;">8</td><td style="text-align:center;">I</td><td style="text-align:center;">9</td><td style="text-align:center;">J</td><td style="text-align:center;">10</td><td style="text-align:center;">K</td><td style="text-align:center;">11</td><td style="text-align:center;">L</td></tr><tr><td style="text-align:center;">12</td><td style="text-align:center;">M</td><td style="text-align:center;">13</td><td style="text-align:center;">N</td><td style="text-align:center;">14</td><td style="text-align:center;">O</td><td style="text-align:center;">15</td><td style="text-align:center;">P</td></tr><tr><td style="text-align:center;">16</td><td style="text-align:center;">Q</td><td style="text-align:center;">17</td><td style="text-align:center;">R</td><td style="text-align:center;">18</td><td style="text-align:center;">S</td><td style="text-align:center;">19</td><td style="text-align:center;">T</td></tr><tr><td style="text-align:center;">20</td><td style="text-align:center;">U</td><td style="text-align:center;">21</td><td style="text-align:center;">V</td><td style="text-align:center;">22</td><td style="text-align:center;">W</td><td style="text-align:center;">23</td><td style="text-align:center;">X</td></tr><tr><td style="text-align:center;">24</td><td style="text-align:center;">Y</td><td style="text-align:center;">25</td><td style="text-align:center;">Z</td><td style="text-align:center;">26</td><td style="text-align:center;">a</td><td style="text-align:center;">27</td><td style="text-align:center;">b</td></tr><tr><td style="text-align:center;">28</td><td style="text-align:center;">c</td><td style="text-align:center;">29</td><td style="text-align:center;">d</td><td style="text-align:center;">30</td><td style="text-align:center;">e</td><td style="text-align:center;">31</td><td style="text-align:center;">f</td></tr><tr><td style="text-align:center;">32</td><td style="text-align:center;">g</td><td style="text-align:center;">33</td><td style="text-align:center;">h</td><td style="text-align:center;">34</td><td style="text-align:center;">i</td><td style="text-align:center;">35</td><td style="text-align:center;">j</td></tr><tr><td style="text-align:center;">36</td><td style="text-align:center;">k</td><td style="text-align:center;">37</td><td style="text-align:center;">l</td><td style="text-align:center;">38</td><td style="text-align:center;">m</td><td style="text-align:center;">39</td><td style="text-align:center;">n</td></tr><tr><td style="text-align:center;">40</td><td style="text-align:center;">o</td><td style="text-align:center;">41</td><td style="text-align:center;">p</td><td style="text-align:center;">42</td><td style="text-align:center;">q</td><td style="text-align:center;">43</td><td style="text-align:center;">r</td></tr><tr><td style="text-align:center;">44</td><td style="text-align:center;">s</td><td style="text-align:center;">45</td><td style="text-align:center;">t</td><td style="text-align:center;">46</td><td style="text-align:center;">u</td><td style="text-align:center;">47</td><td style="text-align:center;">v</td></tr><tr><td style="text-align:center;">48</td><td style="text-align:center;">w</td><td style="text-align:center;">49</td><td style="text-align:center;">x</td><td style="text-align:center;">50</td><td style="text-align:center;">y</td><td style="text-align:center;">51</td><td style="text-align:center;">z</td></tr><tr><td style="text-align:center;">52</td><td style="text-align:center;">0</td><td style="text-align:center;">53</td><td style="text-align:center;">1</td><td style="text-align:center;">54</td><td style="text-align:center;">2</td><td style="text-align:center;">55</td><td style="text-align:center;">3</td></tr><tr><td style="text-align:center;">56</td><td style="text-align:center;">4</td><td style="text-align:center;">57</td><td style="text-align:center;">5</td><td style="text-align:center;">58</td><td style="text-align:center;">6</td><td style="text-align:center;">59</td><td style="text-align:center;">7</td></tr><tr><td style="text-align:center;">60</td><td style="text-align:center;">8</td><td style="text-align:center;">61</td><td style="text-align:center;">9</td><td style="text-align:center;">62</td><td style="text-align:center;">+</td><td style="text-align:center;">63</td><td style="text-align:center;">/</td></tr></tbody></table><h4 id="例子-don" tabindex="-1">例子： “don” <a class="header-anchor" href="#例子-don" aria-label="Permalink to &quot;例子： “don”&quot;">​</a></h4><ol><li>三个一组 -&gt; don</li><li>转换成二进制<br> d: ASCII值 100， 二进制为0110 0100<br> 0: ASCII值 111， 二级制为0110 1111<br> n: ASCII值 110， 二进制为0110 1110</li><li>24个二进制位6个一组，可以分为4组， 每组开头再补充两个0，组成32个二进制位<br> 24个：0110 0100 0110 1111 0110 1110<br> 分为四组，并开头补充0：0001 1001 00000 0110 0010 1110</li><li>将二进制转换成十进制，查找对应的base64值<br> 对应的十进制值为： 25， 6， 60， 46<br> 对应的base64为：ZG8u</li></ol><h4 id="如果不足3个字符s" tabindex="-1">如果不足3个字符s <a class="header-anchor" href="#如果不足3个字符s" aria-label="Permalink to &quot;如果不足3个字符s&quot;">​</a></h4><p>主流程不变，还是转换成二进制，6个二进制位分为一组，最后一组不够6个，就用0补充</p><h3 id="例如-只有两个字符-do" tabindex="-1">例如：只有两个字符 “do” <a class="header-anchor" href="#例如-只有两个字符-do" aria-label="Permalink to &quot;例如：只有两个字符 “do”&quot;">​</a></h3><ul><li>转成二进制 0110 0100 0110 1111</li><li>6个一组，可以分为三组（6，6， 4），最后一组，尾部用2个0补充成6个二进制位：011001 00111 111100，在每组开头补充两个0，00011001 00001111 00111100</li><li>二进制转换成十进制：25， 15， 30，对应的base64值为 ZGe,</li><li>为补充成4个base64一组，尾部再加个=， 所以，最终的值为ZGe=</li></ul><h4 id="另一个例子-只有一个字符-d" tabindex="-1">另一个例子，只有一个字符 ‘d’ <a class="header-anchor" href="#另一个例子-只有一个字符-d" aria-label="Permalink to &quot;另一个例子，只有一个字符 ‘d’&quot;">​</a></h4><p>主流程不变，6个一组，不够6个，尾部用0补充；三个字符，缺n个字符，转成的base64尾部就有n个=</p><h3 id="如何解码" tabindex="-1">如何解码？ <a class="header-anchor" href="#如何解码" aria-label="Permalink to &quot;如何解码？&quot;">​</a></h3><p>编码的逆过程：</p><ol><li>每4个字符一组，查找base64表，找出对应的ASCII值</li><li>将十进制转换成二进制，并去掉每组开头的00</li><li>将剩下的24个二进制位分成3组，分为3个字节</li><li>查找ASCII表，找到每个字节对应的字符</li></ol><p>ASCII表： <img src="'+a+'" alt="ASCII表"></p>',23)])])}const b=e(r,[["render",i]]);export{h as __pageData,b as default};
